// Script: generar_72_fix_prevencion_acordeon.js
// REEMPLAZA generar_71 -- corrige el error "Cannot find name 'tab'"
// que quedaba en el header de Prevencion.

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  // Verificar que no quedo 'tab' residual
  if (filePath.includes('prevencion')) {
    const written = fs.readFileSync(filePath, 'utf8');
    const tabCount = (written.match(/\btab\b/g) || []).length;
    console.log('OK: ' + filePath + ' (referencias a tab: ' + tabCount + ')');
  } else {
    console.log('OK: ' + filePath);
  }
}

escribir('app/prevencion/page.tsx', "");
escribir('app/analisis/page.tsx', "");
